{
  "parameters": {
    "tagName": {
      "type": "String",
      "metadata": { "displayName": "Tag name", "description": "The name of the required tag" }
    },
    "allowedLocations": {
      "type": "Array",
      "metadata": { "displayName": "Allowed locations" },
      "defaultValue": ["eastus", "eastus2"],
      "allowedValues": ["eastus", "eastus2", "westeurope", "australiaeast"]
    }
  }
