{
  "mode": "Indexed",
  "displayName": "Require a tag on resources",
  "description": "Denies creation of resources that do not have the specified tag.",
  "parameters": {
    "tagName": {
      "type": "String",
      "metadata": { "displayName": "Required tag name" }
    }
  },
  "policyRule": {
    "if": {
      "field": "[concat('tags[', parameters('tagName'), ']')]",
      "exists": "false"
    },
    "then": { "effect": "deny" }
  }
}

{
  "mode": "All",
  "displayName": "Audit VMs for approved SKUs",
  "parameters": {
    "listOfAllowedSKUs": {
      "type": "Array",
      "metadata": { "displayName": "Allowed VM SKUs" },
      "defaultValue": ["Standard_D2s_v5", "Standard_D4s_v5", "Standard_D8s_v5"]
    }
  },
  "policyRule": {
    "if": {
      "allOf": [
        { "field": "type", "equals": "Microsoft.Compute/virtualMachines" },
        { "not": { "field": "Microsoft.Compute/virtualMachines/sku.name", "in": "[parameters('listOfAllowedSKUs')]" } }
      ]
    },
    "then": { "effect": "audit" }
  }
}

