# main.tf
resource "azurerm_policy_definition" "deny_public_storage" {
  name         = "deny-public-storage-blob-access"
  policy_type  = "Custom"
  mode         = "Indexed"
  display_name = "Deny public blob access on storage accounts"
  description  = "Prevents storage accounts from allowing public blob access"

  management_group_id = data.azurerm_management_group.corp.id

  metadata = jsonencode({
    version  = "1.0.0"
    category = "Storage"
  })

  policy_rule = file("${path.module}/policies/deny-public-storage.json")
}

# Assign with effect override at Corp-Prod (deny) vs Corp-NonProd (audit)
resource "azurerm_management_group_policy_assignment" "deny_public_storage_prod" {
  name                 = "deny-pub-storage-prod"
  management_group_id  = data.azurerm_management_group.corp_prod.id
  policy_definition_id = azurerm_policy_definition.deny_public_storage.id
  parameters = jsonencode({ effect = { value = "Deny" } })
}

resource "azurerm_management_group_policy_assignment" "audit_public_storage_nonprod" {
  name                 = "audit-pub-storage-nonprod"
  management_group_id  = data.azurerm_management_group.corp_nonprod.id
  policy_definition_id = azurerm_policy_definition.deny_public_storage.id
  parameters = jsonencode({ effect = { value = "Audit" } })
}

{
  "mode": "All",
  "displayName": "Deny NSG rules that allow inbound SSH from any source",
  "policyRule": {
    "if": {
      "allOf": [
        { "field": "type", "equals": "Microsoft.Network/networkSecurityGroups" },
        {
          "count": {
            "field": "Microsoft.Network/networkSecurityGroups/securityRules[*]",
            "where": {
              "allOf": [
                { "field": "Microsoft.Network/networkSecurityGroups/securityRules[*].direction", "equals": "Inbound" },
                { "field": "Microsoft.Network/networkSecurityGroups/securityRules[*].access", "equals": "Allow" },
                { "field": "Microsoft.Network/networkSecurityGroups/securityRules[*].destinationPortRange", "equals": "22" },
                { "field": "Microsoft.Network/networkSecurityGroups/securityRules[*].sourceAddressPrefix", "in": ["*", "Internet", "0.0.0.0/0"] }
              ]
            }
          },
          "greaterOrEquals": 1
        }
      ]
    },
    "then": { "effect": "deny" }
  }
}

{
  "mode": "All",
  "displayName": "Resources in tagged RGs must inherit the cost-center tag",
  "policyRule": {
    "if": {
      "allOf": [
        { "value": "[resourceGroup().tags['cost-center']]", "notEquals": "" },
        { "field": "tags['cost-center']", "exists": "false" }
      ]
    },
    "then": {
      "effect": "modify",
      "details": {
        "roleDefinitionIds": ["/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"],
        "operations": [{
          "operation": "add",
          "field": "tags['cost-center']",
          "value": "[resourceGroup().tags['cost-center']]"
        }]
      }
    }
  }
}

{
  "mode": "All",
  "displayName": "Deploy Log Analytics agent to Windows VMs",
  "parameters": {
    "logAnalyticsWorkspaceId": {
      "type": "String",
      "metadata": { "displayName": "Log Analytics workspace resource ID" }
    }
  },
  "policyRule": {
    "if": {
      "allOf": [
        { "field": "type", "equals": "Microsoft.Compute/virtualMachines" },
        { "field": "Microsoft.Compute/virtualMachines/storageProfile.osDisk.osType", "like": "Windows*" }
      ]
    },
    "then": {
      "effect": "deployIfNotExists",
      "details": {
        "type": "Microsoft.Compute/virtualMachines/extensions",
        "name": "MicrosoftMonitoringAgent",
        "existenceCondition": {
          "allOf": [
            { "field": "Microsoft.Compute/virtualMachines/extensions/publisher", "equals": "Microsoft.EnterpriseCloud.Monitoring" },
            { "field": "Microsoft.Compute/virtualMachines/extensions/provisioningState", "equals": "Succeeded" }
          ]
        },
        "roleDefinitionIds": [
          "/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"
        ],
        "deployment": {
          "properties": {
            "mode": "incremental",
            "parameters": {
              "vmName": { "value": "[field('name')]" },
              "location": { "value": "[field('location')]" },
              "workspaceId": { "value": "[parameters('logAnalyticsWorkspaceId')]" }
            },
            "template": {
              "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
              "contentVersion": "1.0.0.0",
              "parameters": {
                "vmName": { "type": "string" },
                "location": { "type": "string" },
                "workspaceId": { "type": "string" }
              },
              "resources": [{
                "type": "Microsoft.Compute/virtualMachines/extensions",
                "apiVersion": "2023-03-01",
                "name": "[concat(parameters('vmName'), '/MicrosoftMonitoringAgent')]",
                "location": "[parameters('location')]",
                "properties": {
                  "publisher": "Microsoft.EnterpriseCloud.Monitoring",
                  "type": "MicrosoftMonitoringAgent",
                  "typeHandlerVersion": "1.0",
                  "autoUpgradeMinorVersion": true,
                  "settings": { "workspaceId": "[parameters('workspaceId')]" }
                }
              }]
            }
          }
        }
      }
    }
  }
}
